SELECT dietary_item
FROM lifestyle_data
WHERE age = 30;

SELECT COUNT(DISTINCT dietary_item) 
FROM lifestyle_data 
WHERE age BETWEEN 30 AND 40;

SELECT AVG(age) AS average_age
FROM lifestyle_data
WHERE amount > 20;

SELECT AVG(weight) AS avg_weight
FROM health_metrics
WHERE smoking_status = 'Smoker';

SELECT COUNT(*) AS user_count, AVG(age) AS average_age
FROM (
    SELECT DISTINCT user_id, age
    FROM lifestyle_data
    WHERE dietary_item = 'Carrots' AND amount > 25
) AS carrot_consumers;

SELECT user_id, COUNT(*) AS num_metrics
FROM health_metrics
GROUP BY user_id;

SELECT height
FROM health_metrics
WHERE smoking_status = 'Smoker';

SELECT DISTINCT users.name, lifestyle_data.age
FROM users
JOIN lifestyle_data ON users.user_id = lifestyle_data.user_id;

SELECT AVG(average_bmi)
FROM (
    SELECT AVG(bmi) as average_bmi
    FROM health_metrics
    GROUP BY user_id
    HAVING AVG(bmi) > (
        SELECT AVG(bmi) 
        FROM health_metrics
    )
) as subquery;
